"use client";

import {
  IconPlayerPlayFilled,
  IconPlayerPauseFilled,
} from "@tabler/icons-react";
import { cn } from "@/lib/utils";
import { formatTime } from "@/registry/new-york/controls/format";
import { QUALITY_LEVELS } from "@/registry/new-york/controls/quality";
import type { QualityLevel } from "@/registry/new-york/controls/quality";
import type { PlayerState, PlaybackSpeed } from "@/registry/new-york/controls/types";
import { YtcnProgress } from "@/registry/new-york/controls/ytcn-progress";
import { YtcnVolume } from "@/registry/new-york/controls/ytcn-volume";
import { YtcnQuality } from "@/registry/new-york/controls/ytcn-quality";
import { YtcnFullscreen } from "@/registry/new-york/controls/ytcn-fullscreen";

interface YtcnControlsProps {
  /** Full player state object */
  state: PlayerState;
  /** Toggle play/pause */
  onTogglePlay: () => void;
  /** Seek to a specific time in seconds */
  onSeek: (seconds: number) => void;
  /** Set volume (0–100) */
  onVolumeChange: (vol: number) => void;
  /** Toggle mute */
  onToggleMute: () => void;
  /** Set playback speed */
  onSpeedChange: (rate: PlaybackSpeed) => void;
  /** Set quality level */
  onQualityChange: (quality: QualityLevel | "auto") => void;
  /** Toggle fullscreen */
  onToggleFullscreen: () => void;
  /** Whether controls should be visible */
  visible: boolean;
  /**
   * Container ref for portal — ensures dropdown menus render inside the
   * player container for fullscreen visibility.
   */
  containerRef?: React.RefObject<HTMLDivElement | null>;
}

/**
 * YtcnControls — Full controls bar with progress, play/pause, volume,
 * quality/speed settings, and fullscreen toggle.
 *
 * Designed to sit at the bottom of the player container with a gradient
 * overlay. Visibility is controlled by the `visible` prop, typically
 * driven by mouse hover or drag state.
 */
export function YtcnControls({
  state,
  onTogglePlay,
  onSeek,
  onVolumeChange,
  onToggleMute,
  onSpeedChange,
  onQualityChange,
  onToggleFullscreen,
  visible,
  containerRef,
}: YtcnControlsProps) {
  return (
    <div
      className={cn(
        "absolute inset-x-0 bottom-0 z-30 flex flex-col transition-opacity duration-300",
        visible ? "opacity-100" : "pointer-events-none opacity-0"
      )}
    >
      {/* Gradient overlay */}
      <div className="pointer-events-none absolute inset-0 bg-gradient-to-t from-black/80 via-black/30 to-transparent" />

      {/* Progress bar */}
      <div className="relative z-10 px-3">
        <YtcnProgress
          currentTime={state.currentTime}
          duration={state.duration}
          loadedFraction={state.loadedFraction}
          onSeek={onSeek}
        />
      </div>

      {/* Controls row */}
      <div className="relative z-10 flex items-center gap-1 px-3 pb-2.5 pt-1.5">
        {/* Left group */}
        <div className="flex items-center gap-1">
          {/* Play/Pause */}
          <button
            onClick={(e) => {
              e.stopPropagation();
              onTogglePlay();
            }}
            className="flex items-center justify-center rounded-sm p-1.5 text-white transition-colors hover:bg-white/10"
            aria-label={state.isPlaying ? "Pause" : "Play"}
          >
            {state.isPlaying ? (
              <IconPlayerPauseFilled className="size-5" />
            ) : (
              <IconPlayerPlayFilled className="size-5" />
            )}
          </button>

          {/* Volume */}
          <YtcnVolume
            volume={state.volume}
            isMuted={state.isMuted}
            onVolumeChange={onVolumeChange}
            onToggleMute={onToggleMute}
          />

          {/* Time display */}
          <span className="ml-1.5 select-none text-xs tabular-nums text-white/80 font-mono">
            {formatTime(state.currentTime)}
            <span className="text-white/50 mx-1">/</span>
            <span className="text-white/70">{formatTime(state.duration)}</span>
          </span>
        </div>

        {/* Spacer */}
        <div className="flex-1" />

        {/* Right group */}
        <div className="flex items-center gap-0.5">
          {/* Active quality badge */}
          {state.actualQuality &&
            QUALITY_LEVELS[state.actualQuality as QualityLevel] && (
              <span className="text-xs font-semibold text-white/90 px-2 py-1 rounded bg-white/10">
                {QUALITY_LEVELS[state.actualQuality as QualityLevel].label}
              </span>
            )}

          {/* Active speed badge */}
          {state.playbackRate !== 1 && (
            <span className="text-xs font-semibold text-white/90 px-2 py-1 rounded bg-white/10">
              {state.playbackRate}x
            </span>
          )}

          {/* Settings dropdown (quality + speed) */}
          <YtcnQuality
            selectedQuality={state.selectedQuality}
            actualQuality={state.actualQuality}
            availableQualities={state.availableQualities}
            onQualityChange={onQualityChange}
            playbackRate={state.playbackRate}
            onSpeedChange={onSpeedChange}
            containerRef={containerRef}
          />

          {/* Fullscreen */}
          <YtcnFullscreen
            isFullscreen={state.isFullscreen}
            onToggle={onToggleFullscreen}
          />
        </div>
      </div>
    </div>
  );
}

"use client";

import { memo } from "react";
import { cn } from "@/lib/utils";
import { formatTime } from "@/registry/new-york/controls/format";
import { useTimeline } from "@/registry/new-york/controls/use-timeline";

interface YtcnProgressProps {
  /** Current playback position in seconds */
  currentTime: number;
  /** Total video duration in seconds */
  duration: number;
  /** Buffer progress as a fraction from 0 to 1 */
  loadedFraction: number;
  /** Called with the target time in seconds on click or drag */
  onSeek: (seconds: number) => void;
  className?: string;
}

/**
 * YtcnProgress — Timeline scrub bar with hover tooltip, buffer indicator,
 * and drag-to-seek.
 *
 * Memoized because it re-renders on every 250ms poll tick from the player
 * state — memo prevents unnecessary re-renders when only unrelated state
 * changes (like volume or quality) occur.
 */
export const YtcnProgress = memo(function YtcnProgress({
  currentTime,
  duration,
  loadedFraction,
  onSeek,
  className,
}: YtcnProgressProps) {
  const progress = duration > 0 ? (currentTime / duration) * 100 : 0;
  const buffered = loadedFraction * 100;

  const { barRef, isDragging, hoverTime, hoverFraction, handlers } = useTimeline({
    duration,
    onSeek,
  });

  return (
    <div
      ref={barRef}
      className={cn(
        "group/progress relative h-1 w-full cursor-pointer transition-[height] hover:h-1.5",
        className
      )}
      onMouseDown={handlers.onMouseDown}
      onMouseMove={handlers.onMouseMove}
      onMouseLeave={handlers.onMouseLeave}
      onClick={(e) => e.stopPropagation()}
      role="slider"
      aria-valuenow={Math.floor(currentTime)}
      aria-valuemin={0}
      aria-valuemax={Math.floor(duration)}
      aria-label="Video progress"
      tabIndex={0}
    >
      {/* Track background */}
      <div className="absolute inset-0 rounded-full bg-white/20" />

      {/* Buffer indicator */}
      <div
        className="absolute inset-y-0 left-0 rounded-full bg-white/30 transition-[width] duration-500"
        style={{ width: `${buffered}%` }}
      />

      {/* Filled progress */}
      <div
        className="absolute inset-y-0 left-0 rounded-full bg-primary transition-[width] duration-100"
        style={{ width: `${progress}%` }}
      />

      {/* Scrubber dot — visible on hover */}
      <div
        className="absolute top-1/2 -translate-x-1/2 -translate-y-1/2 size-3 rounded-full bg-primary border-2 border-background shadow-lg opacity-0 transition-opacity group-hover/progress:opacity-100"
        style={{ left: `${progress}%` }}
      />

      {/* Hover tooltip */}
      {hoverTime !== null && duration > 0 && (
        <div
          className="absolute -top-8 -translate-x-1/2 rounded bg-background/90 px-1.5 py-0.5 text-xs text-foreground shadow-md pointer-events-none"
          style={{
            left: `${hoverFraction * 100}%`,
          }}
        >
          {formatTime(hoverTime)}
        </div>
      )}
    </div>
  );
});

"use client";

import {
  IconVolume,
  IconVolumeOff,
  IconVolume2,
} from "@tabler/icons-react";
import { Slider } from "@/components/ui/slider";

interface YtcnVolumeProps {
  /** Current volume level (0–100) */
  volume: number;
  /** Whether audio is currently muted */
  isMuted: boolean;
  /** Called with new volume value (0–100) */
  onVolumeChange: (vol: number) => void;
  /** Toggle mute on/off */
  onToggleMute: () => void;
}

/**
 * YtcnVolume — Volume slider with mute toggle.
 *
 * The slider is hidden by default (width: 0) and expands on hover via
 * a CSS transition on the parent group. This matches YouTube's native
 * volume control UX without any JS-driven show/hide state.
 */
export function YtcnVolume({
  volume,
  isMuted,
  onVolumeChange,
  onToggleMute,
}: YtcnVolumeProps) {
  const VolumeIcon =
    isMuted || volume === 0
      ? IconVolumeOff
      : volume < 50
        ? IconVolume2
        : IconVolume;

  return (
    <div className="group/volume flex items-center gap-1">
      <button
        onClick={(e) => {
          e.stopPropagation();
          onToggleMute();
        }}
        className="flex items-center justify-center rounded-sm p-1 text-white transition-colors hover:bg-white/10"
        aria-label={isMuted ? "Unmute" : "Mute"}
      >
        <VolumeIcon className="size-5" />
      </button>
      <div className="w-0 overflow-hidden transition-[width] duration-200 group-hover/volume:w-20">
        <Slider
          value={[isMuted ? 0 : volume]}
          max={100}
          step={1}
          onValueChange={([val]) => onVolumeChange(val)}
          className="w-20 cursor-pointer"
          aria-label="Volume"
          onClick={(e) => e.stopPropagation()}
        />
      </div>
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { IconAdjustments } from "@tabler/icons-react";
import { QUALITY_LEVELS } from "@/registry/new-york/controls/quality";
import type { QualityLevel } from "@/registry/new-york/controls/quality";
import type { PlaybackSpeed } from "@/registry/new-york/controls/types";
import { PLAYBACK_SPEEDS } from "@/registry/new-york/controls/types";

interface YtcnQualityProps {
  /** The quality level the user has selected (or "auto") */
  selectedQuality: QualityLevel | "auto";
  /** The quality level YouTube is actually playing at */
  actualQuality: QualityLevel | "";
  /** Quality levels available for this video */
  availableQualities: QualityLevel[];
  /** Called when the user picks a quality level */
  onQualityChange: (quality: QualityLevel | "auto") => void;
  /** Current playback speed — displayed in the same settings dropdown */
  playbackRate?: number;
  /** Called when the user picks a speed */
  onSpeedChange?: (rate: PlaybackSpeed) => void;
  /**
   * Portal container for fullscreen visibility.
   *
   * By default Radix portals dropdown content to document.body. When the
   * player is in fullscreen mode, the browser only renders elements INSIDE
   * the fullscreen element — anything portaled to body becomes invisible.
   * Passing containerRef.current makes the portal append inside the
   * fullscreen element, keeping the dropdown always visible.
   */
  containerRef?: React.RefObject<HTMLDivElement | null>;
}

/**
 * YtcnQuality — Quality selector dropdown with optional speed picker.
 *
 * Combines quality and speed selection into a single settings dropdown,
 * portaled into the player container for fullscreen compatibility.
 */
export function YtcnQuality({
  selectedQuality,
  actualQuality,
  availableQualities,
  onQualityChange,
  playbackRate,
  onSpeedChange,
  containerRef,
}: YtcnQualityProps) {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <button
          onClick={(e) => e.stopPropagation()}
          className="flex items-center justify-center rounded-sm p-1.5 text-white transition-colors hover:bg-white/10"
          aria-label="Settings"
        >
          <IconAdjustments className="size-5" />
        </button>
      </DropdownMenuTrigger>

      <DropdownMenuContent
        align="end"
        className="w-48"
        container={containerRef?.current ?? undefined}
        onClick={(e) => e.stopPropagation()}
      >
        {/* ── Quality ── */}
        <DropdownMenuLabel>Quality</DropdownMenuLabel>

        <DropdownMenuItem
          onClick={() => onQualityChange("auto")}
          className={cn(
            "cursor-pointer",
            selectedQuality === "auto" && "bg-accent"
          )}
        >
          <span className="flex-1">Auto</span>
          {selectedQuality === "auto" && actualQuality && (
            <span className="text-xs text-muted-foreground ml-1">
              ({QUALITY_LEVELS[actualQuality as QualityLevel]?.label})
            </span>
          )}
          {selectedQuality === "auto" && (
            <span className="text-primary ml-1">✓</span>
          )}
        </DropdownMenuItem>

        {availableQualities.length === 0 ? (
          <DropdownMenuItem disabled>
            <span className="text-muted-foreground text-xs italic">
              Play video to load qualities
            </span>
          </DropdownMenuItem>
        ) : (
          availableQualities.map((quality) => (
            <DropdownMenuItem
              key={quality}
              onClick={() => onQualityChange(quality)}
              className={cn(
                "cursor-pointer",
                selectedQuality === quality && "bg-accent"
              )}
            >
              <span className="flex-1">
                {QUALITY_LEVELS[quality].label}
              </span>
              {selectedQuality === quality && (
                <span className="text-primary">✓</span>
              )}
            </DropdownMenuItem>
          ))
        )}

        {/* ── Speed (optional) ── */}
        {onSpeedChange && (
          <>
            <DropdownMenuSeparator />
            <DropdownMenuLabel>Playback Speed</DropdownMenuLabel>
            {PLAYBACK_SPEEDS.map((speed) => (
              <DropdownMenuItem
                key={speed}
                onClick={() => onSpeedChange(speed)}
                className={cn(
                  "cursor-pointer",
                  playbackRate === speed && "bg-accent"
                )}
              >
                <span className="flex-1">
                  {speed === 1 ? "Normal" : `${speed}x`}
                </span>
                {playbackRate === speed && (
                  <span className="text-primary">✓</span>
                )}
              </DropdownMenuItem>
            ))}
          </>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

"use client";

import { IconMaximize, IconMinimize } from "@tabler/icons-react";

interface YtcnFullscreenProps {
  /** Whether the player is currently in fullscreen mode */
  isFullscreen: boolean;
  /** Toggle fullscreen on/off */
  onToggle: () => void;
}

/**
 * YtcnFullscreen — Fullscreen toggle button.
 *
 * Switches icon between maximize and minimize based on current state.
 */
export function YtcnFullscreen({ isFullscreen, onToggle }: YtcnFullscreenProps) {
  return (
    <button
      onClick={(e) => {
        e.stopPropagation();
        onToggle();
      }}
      className="flex items-center justify-center rounded-sm p-1.5 text-white transition-colors hover:bg-white/10"
      aria-label={isFullscreen ? "Exit fullscreen" : "Fullscreen"}
    >
      {isFullscreen ? (
        <IconMinimize className="size-5" />
      ) : (
        <IconMaximize className="size-5" />
      )}
    </button>
  );
}

import type { QualityLevel } from "@/lib/ytcn/quality";

/* ================================================================ */
/*  Playback Speed                                                   */
/* ================================================================ */

export type PlaybackSpeed = 0.25 | 0.5 | 0.75 | 1 | 1.25 | 1.5 | 1.75 | 2;

export const PLAYBACK_SPEEDS: PlaybackSpeed[] = [
  0.25, 0.5, 0.75, 1, 1.25, 1.5, 1.75, 2,
];

/* ================================================================ */
/*  Player State                                                     */
/* ================================================================ */

export interface PlayerState {
  isPlaying: boolean;
  isMuted: boolean;
  volume: number; // 0–100
  currentTime: number; // seconds
  duration: number; // seconds
  loadedFraction: number; // 0–1 buffer progress
  isLoading: boolean;
  isFullscreen: boolean;
  playbackRate: PlaybackSpeed;
  selectedQuality: QualityLevel | "auto";
  actualQuality: QualityLevel | "";
  availableQualities: QualityLevel[];
}

/* ================================================================ */
/*  Player Options                                                   */
/* ================================================================ */

export interface YtcnPlayerOptions {
  /** YouTube video ID (the 11-character string, not a full URL) */
  videoId: string;
  /** Start playback automatically. Browsers require muted audio for this. */
  autoplay?: boolean;
  /** Initial quality hint — applied via both vq and setPlaybackQualityRange */
  defaultQuality?: QualityLevel | "auto";
  /** Initial playback rate */
  defaultSpeed?: PlaybackSpeed;
  /** Resume from this timestamp (seconds) */
  startAt?: number;
  /** Fired when the video reaches its end */
  onEnd?: () => void;
  /** Polled every 250ms during playback */
  onTimeUpdate?: (currentTime: number, duration: number) => void;
  /** Fired when the actual quality level changes */
  onQualityChange?: (quality: string) => void;
  /** Fired when the playback rate changes */
  onPlaybackRateChange?: (rate: number) => void;
}

/* ================================================================ */
/*  Controls Interface                                               */
/* ================================================================ */

export interface PlayerControls {
  play: () => void;
  pause: () => void;
  togglePlay: () => void;
  seekTo: (seconds: number) => void;
  seekRelative: (delta: number) => void;
  setVolume: (vol: number) => void;
  toggleMute: () => void;
  setSpeed: (rate: PlaybackSpeed) => void;
  setQuality: (quality: QualityLevel | "auto") => void;
  toggleFullscreen: () => void;
}

/* ================================================================ */
/*  Keyboard Shortcut Bindings                                       */
/* ================================================================ */

export interface KeyboardBindings {
  play?: string;
  mute?: string;
  fullscreen?: string;
  seekBack?: string;
  seekForward?: string;
}

export const DEFAULT_KEYBOARD_BINDINGS: Required<KeyboardBindings> = {
  play: " ",
  mute: "m",
  fullscreen: "f",
  seekBack: "ArrowLeft",
  seekForward: "ArrowRight",
};

/**
 * QUALITY_LEVELS — YouTube quality level identifiers mapped to human labels.
 *
 * The `order` field defines sort priority: 0 = highest quality, 7 = lowest.
 * These string keys are the exact values YouTube's IFrame API returns from
 * `getAvailableQualityLevels()` and accepts in `setPlaybackQuality()`.
 */
export const QUALITY_LEVELS = {
  highres: { label: "4K+", order: 0 },
  hd2160: { label: "4K", order: 1 },
  hd1440: { label: "1440p", order: 2 },
  hd1080: { label: "1080p", order: 3 },
  hd720: { label: "720p", order: 4 },
  large: { label: "480p", order: 5 },
  medium: { label: "360p", order: 6 },
  small: { label: "240p", order: 7 },
} as const;

export type QualityLevel = keyof typeof QUALITY_LEVELS;

/**
 * enforceQuality — Dual-strategy quality enforcement.
 *
 * Strategy B (JS API lock): Called after onReady AND on every PLAYING state
 * change. Sets both min and max quality to the same level, forcing YouTube
 * to stay within that exact range. This is what makes lower qualities like
 * 360p/240p actually stick — the vq playerVar (Strategy A, applied at player
 * creation time) alone is not enough for low qualities because YouTube may
 * silently upgrade them if it detects a fast connection.
 *
 * To release the lock and return to adaptive streaming, we set the range
 * from "small" to "highres" which allows YouTube full freedom.
 *
 * Strategy A (vq playerVar) is applied separately at player creation time
 * in the loader — see use-ytcn-player.ts for that path.
 */
export function enforceQuality(
  player: YT.Player | null,
  quality: QualityLevel | "auto"
): void {
  if (!player) return;
  try {
    if (quality === "auto") {
      // Release the quality lock — let YouTube choose freely
      if (typeof (player as any).setPlaybackQualityRange === "function") {
        (player as any).setPlaybackQualityRange("small", "highres");
      }
    } else {
      // Lock both min and max to the same level
      if (typeof (player as any).setPlaybackQualityRange === "function") {
        (player as any).setPlaybackQualityRange(quality, quality);
      }
      // Fallback: also call the single-quality setter if available
      if (typeof (player as any).setPlaybackQuality === "function") {
        (player as any).setPlaybackQuality(quality);
      }
    }
  } catch {
    /* YouTube API calls can throw if the player is in a bad state */
  }
}

/**
 * Filters and sorts raw quality strings from getAvailableQualityLevels()
 * into typed, ordered QualityLevel values.
 */
export function parseAvailableQualities(levels: string[]): QualityLevel[] {
  return levels
    .filter((q): q is QualityLevel => q in QUALITY_LEVELS)
    .sort((a, b) => QUALITY_LEVELS[a].order - QUALITY_LEVELS[b].order);
}

/**
 * formatTime — Converts seconds to a human-readable timestamp string.
 *
 * Returns "H:MM:SS" for videos ≥ 1 hour, "M:SS" otherwise.
 * Handles edge cases: negative values, NaN, Infinity all return "0:00".
 */
export function formatTime(seconds: number): string {
  if (!isFinite(seconds) || seconds < 0) return "0:00";
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const s = Math.floor(seconds % 60);
  if (h > 0) {
    return `${h}:${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
  }
  return `${m}:${String(s).padStart(2, "0")}`;
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

interface UseTimelineOptions {
  /** Total video duration in seconds */
  duration: number;
  /** Called with the target time in seconds on click or drag */
  onSeek: (seconds: number) => void;
}

interface UseTimelineReturn {
  barRef: React.RefObject<HTMLDivElement | null>;
  isDragging: boolean;
  hoverTime: number | null;
  hoverFraction: number;
  handlers: {
    onMouseDown: (e: React.MouseEvent) => void;
    onMouseMove: (e: React.MouseEvent) => void;
    onMouseLeave: () => void;
  };
}

/**
 * useTimeline — Manages progress bar interaction state.
 *
 * Handles hover position tracking, drag-to-seek with window-level
 * mousemove/mouseup listeners (so dragging works even when cursor leaves
 * the bar), and converts pixel positions to time values.
 *
 * Returns a barRef to attach to the progress bar container, reactive
 * state (isDragging, hoverTime), and event handlers.
 */
export function useTimeline({ duration, onSeek }: UseTimelineOptions): UseTimelineReturn {
  const barRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [hoverTime, setHoverTime] = useState<number | null>(null);
  const [hoverFraction, setHoverFraction] = useState(0);

  const getTimeFromPosition = useCallback(
    (clientX: number): number => {
      const bar = barRef.current;
      if (!bar || duration <= 0) return 0;
      const rect = bar.getBoundingClientRect();
      const ratio = Math.max(0, Math.min(1, (clientX - rect.left) / rect.width));
      return ratio * duration;
    },
    [duration]
  );

  const getFractionFromPosition = useCallback(
    (clientX: number): number => {
      const bar = barRef.current;
      if (!bar) return 0;
      const rect = bar.getBoundingClientRect();
      return Math.max(0, Math.min(1, (clientX - rect.left) / rect.width));
    },
    []
  );

  const onMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();
      setIsDragging(true);
      const time = getTimeFromPosition(e.clientX);
      const fraction = getFractionFromPosition(e.clientX);
      setHoverFraction(fraction);
      onSeek(time);
    },
    [getTimeFromPosition, getFractionFromPosition, onSeek]
  );

  const onMouseMove = useCallback(
    (e: React.MouseEvent) => {
      const time = getTimeFromPosition(e.clientX);
      const fraction = getFractionFromPosition(e.clientX);
      setHoverTime(time);
      setHoverFraction(fraction);
      if (isDragging) {
        onSeek(time);
      }
    },
    [getTimeFromPosition, getFractionFromPosition, isDragging, onSeek]
  );

  const onMouseLeave = useCallback(() => {
    if (!isDragging) {
      setHoverTime(null);
    }
  }, [isDragging]);

  // Window-level listeners for drag continuation outside the bar
  useEffect(() => {
    if (!isDragging) return;

    const handleMove = (e: MouseEvent) => {
      const time = getTimeFromPosition(e.clientX);
      const fraction = getFractionFromPosition(e.clientX);
      setHoverTime(time);
      setHoverFraction(fraction);
      onSeek(time);
    };

    const handleUp = () => {
      setIsDragging(false);
      setHoverTime(null);
    };

    window.addEventListener("mousemove", handleMove);
    window.addEventListener("mouseup", handleUp);
    return () => {
      window.removeEventListener("mousemove", handleMove);
      window.removeEventListener("mouseup", handleUp);
    };
  }, [isDragging, getTimeFromPosition, getFractionFromPosition, onSeek]);

  return {
    barRef,
    isDragging,
    hoverTime,
    hoverFraction,
    handlers: {
      onMouseDown,
      onMouseMove,
      onMouseLeave,
    },
  };
}
